mapper.select:
SELECT id, user_id, phrase_date, phrase_kr, meaning_en, romanization, when_to_use, formality_level,
       similar_expressions::text AS similar_expressions, learned, model_used, created_at
FROM daily_phrases
WHERE user_id = #{userId}
  AND phrase_date = #{phraseDate}

SELECT id, user_id, phrase_date, phrase_kr, meaning_en, romanization, when_to_use, formality_level,
       similar_expressions::text AS similar_expressions, learned, model_used, created_at
FROM daily_phrases
WHERE id = #{id}
  AND user_id = #{userId}

SELECT phrase_kr
FROM daily_phrases
WHERE user_id = #{userId}
ORDER BY phrase_date DESC
LIMIT #{limit}

mapper.update:
UPDATE daily_phrases
SET learned = #{learned}
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM daily_phrases
WHERE id = #{id}
  AND user_id = #{userId}
